import React, { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import API from "../services/api";

const timeSlots = [
  "10:00 AM",
  "11:00 AM",
  "12:00 PM",
  "02:00 PM",
  "03:00 PM",
  "04:00 PM",
];

const Booking = () => {
  const { id } = useParams();

  const [expert, setExpert] = useState(null);
  const [bookedSlots, setBookedSlots] = useState([]);

  const [form, setForm] = useState({
    name: "",
    email: "",
    phone: "",
    date: "",
    time: "",
    notes: "",
  });

  useEffect(() => {
    fetchExpert();
  }, []);

  const fetchExpert = async () => {
    try {
      const res = await API.get(`/experts/${id}`);
      setExpert(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const fetchBookedSlots = async (date) => {
    try {
      const res = await API.get(
        `/bookings?expertId=${id}&date=${date}`
      );
      const times = res.data.map((b) => b.time);
      setBookedSlots(times);
    } catch (err) {
      console.error(err);
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;

    setForm({ ...form, [name]: value });

    if (name === "date") {
      fetchBookedSlots(value);
    }
  };

  const selectSlot = (slot) => {
    if (bookedSlots.includes(slot)) return;
    setForm({ ...form, time: slot });
  };

  const bookSlot = async () => {
    if (!form.name || !form.email || !form.date || !form.time) {
      alert("Fill all required fields");
      return;
    }

    try {
      await API.post("/bookings", {
        ...form,
        expertId: id,
      });

      alert("Booking successful 🎉");

      fetchBookedSlots(form.date);

      setForm({
        name: "",
        email: "",
        phone: "",
        date: "",
        time: "",
        notes: "",
      });
    } catch (err) {
      alert(err.response?.data?.message || "Booking failed");
    }
  };

  if (!expert) return <h2>Loading...</h2>;

  return (
    <div style={{ padding: "40px" }}>
      <h1>{expert.name}</h1>
      <p>📂 {expert.category}</p>
      <p>🧠 {expert.experience} years</p>
      <p>⭐ {expert.rating}</p>

      <h2>Select Date</h2>
      <input type="date" name="date" onChange={handleChange} />

      {form.date && (
        <>
          <h2>Available Slots</h2>

          <div style={{ display: "flex", gap: "10px", flexWrap: "wrap" }}>
            {timeSlots.map((slot) => {
              const isBooked = bookedSlots.includes(slot);
              const isSelected = form.time === slot;

              return (
                <button
                  key={slot}
                  onClick={() => selectSlot(slot)}
                  disabled={isBooked}
                  style={{
                    padding: "10px",
                    background: isBooked
                      ? "gray"
                      : isSelected
                      ? "green"
                      : "#eee",
                    color: isBooked ? "white" : "black",
                  }}
                >
                  {slot}
                </button>
              );
            })}
          </div>
        </>
      )}

      <h2>Enter Details</h2>

      <input name="name" placeholder="Name" onChange={handleChange} />
      <input name="email" placeholder="Email" onChange={handleChange} />
      <input name="phone" placeholder="Phone" onChange={handleChange} />
      <textarea name="notes" placeholder="Notes" onChange={handleChange} />

      <br /><br />
      <button onClick={bookSlot}>Book Now</button>
    </div>
  );
};

export default Booking;
